import React, { useState } from "react";
import { ChevronLeft, Info } from "lucide-react";
import { useCurrency } from "../context/CurrencyContext";

export default function SavingsWithdrawScreen({ onBack, onConfirm, savingsBalance  }) {
  const { formatAmount } = useCurrency();
  const [amount, setAmount] = useState('');

  return (
    <div className="flex flex-col h-full bg-white animate-in fade-in duration-300">

      {/* Header */}
      <div className="flex items-center gap-3 px-6 py-4 sticky top-0 bg-white z-10">
        <button onClick={onBack} className="p-2 hover:bg-gray-100 rounded-full">
          <ChevronLeft className="w-6 h-6 text-gray-800" />
        </button>
        <h1 className="text-xl font-bold text-gray-900">Withdraw Savings</h1>
      </div>

      {/* Scrollable Content */}
      <div className="flex-1 overflow-y-auto px-6 pb-32">
        <div className="bg-emerald-50 border border-emerald-100 p-8 rounded-[2.5rem] text-[#00875A] mb-8">
          <p className="opacity-70 text-sm font-bold uppercase tracking-widest mb-1">
            Locked Savings
          </p>
          <h2 className="text-4xl font-black">{formatAmount(savingsBalance)}</h2>
        </div>

        <div className="space-y-4">
          <label className="text-sm font-bold text-gray-700 ml-1">
            Withdraw Amount
          </label>
          <input
            type="number"
            value={amount}
            onChange={(e) => setAmount(e.target.value)}
            placeholder={formatAmount(0)}
            className="w-full p-5 rounded-3xl bg-gray-50 border border-gray-100 outline-none focus:border-[#00875A] text-2xl font-black text-center"
          />

          <div className="flex gap-3 bg-blue-50 p-4 rounded-2xl mt-4">
            <Info className="text-blue-500 shrink-0" size={20} />
            <p className="text-xs text-blue-700 font-medium leading-relaxed">
              Withdrawing from your savings vault may affect your interest
              progress for the current month.
            </p>
          </div>

          {/* Fixed Action */}
          <div className="pb-64 bg-white border-t mt-6">
            <button
              onClick={() => onConfirm({ amount: Number(amount) })}
              className="w-full py-4 rounded-2xl font-bold text-white bg-[#00875A] shadow-lg"
            >
              Move to Balance
            </button>
          </div>
        </div>
      </div>
    </div>
  );
}
